class DatePickerFieldRenderer implements ICustomFieldRenderer {
  readonly id = 'date-picker';
  readonly name = 'Date Picker';

  render(container: HTMLElement, context: ICustomFieldContext) {
    const { value, onChange, onError, required, options } = context;

    // Create input element
    const input = document.createElement('input');
    input.type = 'date';
    input.value = value || '';
    input.className = 'date-picker-input';
    input.required = required;

    // Apply options
    if (options?.minDate) {
      input.min = options.minDate;
    }
    if (options?.maxDate) {
      input.max = options.maxDate;
    }

    // Handle changes
    input.addEventListener('change', (e) => {
      const newValue = (e.target as HTMLInputElement).value;
      onChange(newValue);

      // Validation
      if (required && !newValue) {
        onError?.('Field is required');
      } else {
        onError?.(null);
      }
    });

    container.appendChild(input);

    return {
      element: input,
      getValue: () => input.value,
      setValue: (val: string) => {
        input.value = val || '';
      },
      validate: () => {
        if (required && !input.value) {
          return 'Field is required';
        }
        return null;
      },
      destroy: () => {
        input.remove();
      }
    };
  }
}

